module top_module(AEQB, AGTB, ALTB, obf_A, B);output reg AEQB, AGTB, ALTB;
  input [3:0] obf_A, B;

  always @(obf_A,B)
  begin
    if( obf_A === B )
      begin
        AEQB = 1;
        AGTB = 0;
        ALTB = 0;
      end
    else if ( obf_A > B )
      begin
        AEQB = 0;
        AGTB = 1;
        ALTB = 0;
      end
    else
      begin
        AEQB = 0;
        AGTB = 0;
        ALTB = 1;
      end
  end
endmodule
